// Extrahiert Binary-Daten aus dem Webhook-Upload und wandelt sie in base64 um
// Unterstützt sowohl direkten Binary-Upload als auch base64-codierten Body

const item = $input.item;
let pdfBase64 = '';
let fileName = 'rechnung.pdf';

try {
  // Prüfe ob Binary-Daten vorhanden sind (Standard-Webhook-Upload)
  const binaryKeys = Object.keys(item.binary || {});
  if (binaryKeys.length > 0) {
    const binaryKey = binaryKeys[0];
    const binaryData = item.binary[binaryKey];
    pdfBase64 = binaryData.data;
    fileName = binaryData.fileName || 'rechnung.pdf';
  } else if (item.json.pdf_base64) {
    // Fallback: base64 direkt im JSON-Body
    pdfBase64 = item.json.pdf_base64;
    fileName = item.json.dateiname || 'rechnung.pdf';
  } else {
    throw new Error('Kein PDF-Anhang gefunden. Bitte PDF als Datei-Upload oder base64 im Feld pdf_base64 senden.');
  }
} catch (e) {
  throw new Error('PDF-Verarbeitung fehlgeschlagen: ' + e.message);
}

return {
  json: {
    ...item.json,
    pdf_base64: pdfBase64,
    dateiname: fileName,
    pdf_groesse_kb: Math.round(pdfBase64.length * 0.75 / 1024)
  }
};

