const item = $input.item;
const anthropicResponse = item.json;

// Claude-Antwort parsen
let extrahiert = {};
let parseError = null;

try {
  const content = anthropicResponse.content[0].text;
  // JSON aus der Antwort extrahieren (robuster Parser)
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error('Kein JSON in Claude-Antwort gefunden');
  extrahiert = JSON.parse(jsonMatch[0]);
} catch (e) {
  parseError = 'LLM-Parse-Fehler: ' + e.message;
}

// Validierungslogik
const fehler = [];
const warnungen = [];

if (parseError) {
  fehler.push(parseError);
} else {
  // Pflichtfelder
  if (!extrahiert.lieferant_name) fehler.push('Lieferant nicht erkannt');
  if (!extrahiert.rechnungsnummer) fehler.push('Rechnungsnummer fehlt');
  if (!extrahiert.rechnungsdatum) fehler.push('Rechnungsdatum fehlt');
  if (!extrahiert.bruttobetrag || extrahiert.bruttobetrag <= 0) fehler.push('Bruttobetrag ungültig oder null');
  if (!extrahiert.nettobetrag || extrahiert.nettobetrag <= 0) fehler.push('Nettobetrag ungültig oder null');

  // Plausibilitätsprüfung: Brutto = Netto * (1 + MwSt/100)
  if (extrahiert.nettobetrag && extrahiert.mwst_satz !== null && extrahiert.bruttobetrag) {
    const berechnetesBrutto = Math.round(extrahiert.nettobetrag * (1 + extrahiert.mwst_satz / 100) * 100) / 100;
    const differenz = Math.abs(berechnetesBrutto - extrahiert.bruttobetrag);
    if (differenz > 0.05) {
      warnungen.push(`Brutto-Plausibilität: Erwartet ${berechnetesBrutto}, gefunden ${extrahiert.bruttobetrag} (Diff: ${differenz.toFixed(2)})`);
    }
  }

  // Datum-Prüfung
  if (extrahiert.rechnungsdatum) {
    const rechnungsDate = new Date(extrahiert.rechnungsdatum);
    const heute = new Date();
    const diffTage = (heute - rechnungsDate) / (1000 * 60 * 60 * 24);
    if (diffTage > 180) warnungen.push(`Rechnungsdatum liegt ${Math.round(diffTage)} Tage zurück – bitte prüfen`);
    if (rechnungsDate > heute) warnungen.push('Rechnungsdatum liegt in der Zukunft');
  }

  // IBAN-Format-Check (einfach)
  if (extrahiert.iban && !/^[A-Z]{2}[0-9]{2}[A-Z0-9]{1,30}$/.test(extrahiert.iban.replace(/\s/g, ''))) {
    warnungen.push('IBAN-Format ungewöhnlich – bitte manuell prüfen');
  }
}

const status = fehler.length > 0 ? 'FEHLER' : warnungen.length > 0 ? 'WARNUNG' : 'OK';

return {
  json: {
    ...item.json,
    // Metadaten aus vorherigen Schritten erhalten
    workflow_id: $('Set: Eingangsmetadaten').item.json.workflow_id,
    empfangen_am: $('Set: Eingangsmetadaten').item.json.empfangen_am,
    dateiname: $('HTTP: PDF-Daten vorbereiten (Base64)').item.json.dateiname,
    // Extrahierte Daten
    rechnung: extrahiert,
    validierung: {
      status: status,
      fehler: fehler,
      warnungen: warnungen,
      geprueft_am: new Date().toISOString()
    }
  }
};

// DATEV Buchungsstapel v700 – CSV-Format
// Dokumentation: DATEV-Schnittstellen-Beschreibung Buchungsdatentransfer

const item = $input.item;
const r = item.json.rechnung;

// Hilfsfunktion: Datum von YYYY-MM-DD zu DDMM (DATEV-Format)
function toDatevDatum(isoDate) {
  if (!isoDate) return '';
  const parts = isoDate.split('-');
  if (parts.length !== 3) return '';
  return parts[2] + parts[1]; // TTMM
}

// Konto-Logik (vereinfacht – mit Steuerberater abstimmen)
const mwstSatz = r.mwst_satz || 19;
let steuerSchluessel = '9'; // 9 = Vorsteuer 19%
if (mwstSatz === 7) steuerSchluessel = '8'; // 8 = Vorsteuer 7%
if (mwstSatz === 0) steuerSchluessel = '0';

// DATEV-Header (Zeile 1 + Zeile 2 sind Pflicht)
const header1 = '"EXTF";700;21;"Buchungsstapel";7;"";"";"";"";"";"";"";"";"";"";""';
const header2 = 'Umsatz (ohne Soll/Haben-Kz);Soll/Haben-Kennzeichen;WKZ Umsatz;Kurs;Basis-Umsatz;WKZ Basis-Umsatz;Konto;Gegenkonto (ohne BU-Schlüssel);BU-Schlüssel;Belegdatum;Belegfeld 1;Belegfeld 2;Skonto;Buchungstext;Postensperre;Diverse Adressnummer;Geschäftspartnerbank;Sachverhalt;Zinssperre;Beleglink;Beleginfo - Art 1;Beleginfo - Inhalt 1;KOST1 - Kostenstelle;KOST2 - Kostenstelle;Kost-Menge;EU-Land u. UStID;EU-Steuersatz;Abw. Versteuerungsart;Sachverhalt L+L;Funktionsergänzung;BU 49 Hauptfunktionstyp;BU 49 Hauptfunktionsnummer;BU 49 Funktionsergänzung;Zusatzinformation - Art 1;Zusatzinformation- Inhalt 1;Stück;Gewicht;Zahlweise;Forderungsart;Veranlagungsjahr;Zugeordnete Fälligkeit;Skontotyp;Auftragsnummer;Buchungstyp;USt-Schlüssel (Anzahlungen);EU-Land (Anzahlungen);Sachverhalt (Anzahlungen);EU-Steuersatz (Anzahlungen);Erlöskonto (Anzahlungen);Herkunft-Kz;Buchungs GUID;KOST-Datum;SEPA-Mandatsreferenz;Skontosperre;Gesellschaftername;Beteiligtennummer;Identifikationsnummer;Zeichnernummer;Postensperre bis;Bezeichnung SoBil-Sachverhalt;Kennzeichen SoBil-Buchung;Festschreibung;Leistungsdatum;Leistungsdatum Ende';

// Betrag formatieren (DATEV: Komma als Dezimalzeichen, kein Tausendertrennzeichen)
const betrag = r.nettobetrag ? r.nettobetrag.toFixed(2).replace('.', ',') : '0,00';
const buchungstext = `${r.lieferant_name || 'Unbekannt'} ${r.rechnungsnummer || ''}`.substring(0, 60);
const belegdatum = toDatevDatum(r.rechnungsdatum);
const belegfeld1 = (r.rechnungsnummer || '').substring(0, 36);
const debitorKonto = '{{INDIVIDUELL: datev-konto-debitor}}';
const gegenkonto = '{{INDIVIDUELL: datev-gegenkonto-vorsteuer}}';

// Buchungszeile
const buchungszeile = [
  betrag,           // Umsatz
  'S',              // Soll/Haben
  'EUR',            // Währung
  '',               // Kurs
  '',               // Basis-Umsatz
  '',               // WKZ Basis-Umsatz
  debitorKonto,     // Konto
  gegenkonto,       // Gegenkonto
  steuerSchluessel, // BU-Schlüssel
  belegdatum,       // Belegdatum TTMM
  belegfeld1,       // Belegfeld 1 (Rechnungsnummer)
  '',               // Belegfeld 2
  '',               // Skonto
  `"${buchungstext}"`, // Buchungstext
  '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', ''
].join(';');

const csvContent = [header1, header2, buchungszeile].join('\n');

return {
  json: {
    ...item.json,
    datev_csv: csvContent,
    datev_dateiname: `DATEV_${item.json.workflow_id}_${r.rechnungsnummer || 'unbekannt'}.csv`
  }
};

